import ast
import operator

def evaluate_expression(expr: str) -> str:
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        if isinstance(node, ast.Num):  # For Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # For Python >= 3.8
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Only numeric constants are allowed")
        elif isinstance(node, ast.BinOp):
            if type(node.op) in operators:
                left = eval_node(node.left)
                right = eval_node(node.right)
                return operators[type(node.op)](left, right)
            else:
                raise ValueError(f"Operator {type(node.op).__name__} is not allowed")
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in operators:
                operand = eval_node(node.operand)
                return operators[type(node.op)](operand)
            else:
                raise ValueError(f"Unary operator {type(node.op).__name__} is not allowed")
        elif isinstance(node, ast.Expression):
            return eval_node(node.body)
        else:
            raise ValueError(f"Node type {type(node).__name__} is not allowed")

    try:
        # Parse the expression
        parsed = ast.parse(expr, mode='eval')
        # Evaluate the parsed expression
        result = eval_node(parsed)
        # Return the result as a string
        return str(result)
    except Exception:
        # If any error occurs, return an empty string
        return ""

import json
import yaml
from yaml import Loader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r', encoding='utf-8') as file:
            try:
                yaml_data = yaml.safe_load(file)
                if yaml_data is None:
                    return 'Error: Empty YAML file'
                try:
                    json_string = json.dumps(yaml_data, ensure_ascii=False)
                    return json_string
                except (TypeError, ValueError) as e:
                    return f'Error: Cannot convert to JSON - {str(e)}'
            except yaml.YAMLError as e:
                return f'Error: Invalid YAML content - {str(e)}'
    except FileNotFoundError:
        return 'Error: File not found'
    except PermissionError:
        return 'Error: Permission denied'
    except OSError as e:
        return f'Error: OS error occurred - {str(e)}'

def get_user(cursor: sqlite3.Cursor, username: str, password: str) -> str | None:
    if not username or not password:
        return None

    try:
        cursor.execute(
            "SELECT userInfo FROM users WHERE username = ? AND password = ?",
            (username, password)
        )
        result = cursor.fetchone()
        return result[0] if result else None
    except sqlite3.Error:
        return None

