import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    if not isinstance(xml_string, str):
        raise TypeError("xml_string must be a string")

    # Limit XML size to prevent DoS attacks (10MB limit)
    max_size = 10 * 1024 * 1024
    if len(xml_string.encode('utf-8')) > max_size:
        raise ValueError("XML string exceeds maximum allowed size")

    try:
        # Use fromstring for better security with string input
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML format: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error parsing XML: {str(e)}")

