from flask import Flask, request, escape, render_template
import urllib

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    '''
    module_name = request.args.get('module', 'urllib')

    # Only allow urllib module for security
    if module_name != 'urllib':
        return render_template('error.html', message="Error: Only urllib module is allowed"), 400

    try:
        # Use pre-imported module instead of dynamic import
        module = urllib

        # Get version safely
        version = getattr(module, '__version__', 'Unknown')

        # Use template engine to prevent XSS
        return render_template('index.html', module_name=module_name, version=version)
    except Exception as e:
        return render_template('error.html', message=f"Error: {str(e)}"), 500

if __name__ == '__main__':
    app.run(debug=False)

