from Crypto.PublicKey import DSA

def generate_private_key():
    '''
    Generate a private key using DSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = DSA.generate(2048)
    return key.export_key(format='OpenSSH')

import os
from tempfile import NamedTemporaryFile


def write_results(results):
    '''
    Create a temporary file and write the results to it
    Returns the path to the temporary file
    '''
    try:
        with NamedTemporaryFile(mode='w', delete=False, suffix='.txt') as tmp_file:
            if isinstance(results, (list, tuple)):
                tmp_file.writelines(str(r) + '\n' for r in results)
            else:
                tmp_file.write(str(results))
            return tmp_file.name
    except (IOError, OSError) as e:
        raise RuntimeError(f"Failed to write results to temporary file: {e}")

import re
import os
from werkzeug.utils import secure_filename
from flask import request, Flask, jsonify

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max file size

# Allowed file extensions
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def is_valid_username(username):
    """Validate username to prevent injection attacks"""
    return bool(re.match(r'^[a-zA-Z0-9_-]+$', username))

@app.route('/upload', methods=['POST'])
def upload():
    try:
        # Get username from form data
        username = request.form.get('username', '')

        # Validate username
        if not username or not is_valid_username(username):
            return jsonify({'error': 'Invalid username'}), 400

        # Check if file is in request
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400

        file = request.files['file']

        # Check if file is selected
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400

        # Validate file extension
        if not allowed_file(file.filename):
            return jsonify({'error': 'File type not allowed'}), 400

        # Secure the filename
        filename = secure_filename(file.filename)

        # Search for username in filename (case-insensitive)
        username_found = bool(re.search(re.escape(username), filename, re.IGNORECASE))

        return jsonify({
            'username': username,
            'filename': filename,
            'username_in_filename': username_found
        })

    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(debug=False)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    try:
        # Check if request has data
        if not request.data:
            return jsonify({'error': 'No data provided'}), 400

        # Get YAML data from request
        yaml_data = request.get_data(as_text=True)

        # Safely parse YAML using safe_load to prevent code execution
        parsed_data = yaml.safe_load(yaml_data)

        # Validate parsed data is not None
        if parsed_data is None:
            return jsonify({'error': 'Invalid YAML data'}), 400

        return jsonify(parsed_data), 200

    except yaml.YAMLError as e:
        return jsonify({'error': 'YAML parsing error', 'details': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Internal server error', 'details': str(e)}), 500
